netlist_common_header:
* Skynet Analog Agent - differential_pair
* NMOS differential pair with PMOS active loads and ideal tail current
.include "{MODEL_LIBRARY}"
.options plotwinsize=0
.param VDD={VDD}
.param CL={CL}
.param VINCM={VINCM}
.param VBP={VBP}
.param ITAIL={ITAIL}
.param VID={VID}
.param VID_AC={VID_AC}
.param VIN_STEP={VIN_STEP}
.param TRISE={TRISE}
.param TFALL={TFALL}
.param TPER={TPER}
.param TWIDTH={TWIDTH}
.param TSTOP={TSTOP}
.param TSTEP={TSTEP}
.param WN={WN}
.param LN={LN}
.param MN={MN}
.param WP={WP}
.param LP={LP}
.param MP={MP}

VDD_SRC VDD VSS {VDD}
VBP_SRC VBP VSS {VBP}
ITAIL TAIL VSS {ITAIL}

M_NINP VOUTP VINP TAIL VSS N_50n W={WN} L={LN} m={MN}
M_NINN VOUTN VINN TAIL VSS N_50n W={WN} L={LN} m={MN}
M_PLOADP VOUTP VBP VDD VDD P_50n W={WP} L={LP} m={MP}
M_PLOADN VOUTN VBP VDD VDD P_50n W={WP} L={LP} m={MP}

CLOADP VOUTP VSS {CL}
CLOADN VOUTN VSS {CL}

.save V(VINP) V(VINN) V(VOUTP) V(VOUTN) V(TAIL) V(VBP) I(VDD_SRC) I(ITAIL)

analysis_templates.op:
VVINP VINP VSS {VINCM}
VVINN VINN VSS {VINCM}
.op
.end

analysis_templates.dc:
VVINP VINP VSS {VINCM + VID/2}
VVINN VINN VSS {VINCM - VID/2}
.dc param VID -20m 20m 0.2m
.end
